import React, { useState, useEffect} from 'react';
import axios from 'axios';

const MicrosoftTeams = () => {
  const [contacts, setContacts] = useState([]);
  const [loadingContacts, setLoadingContacts] = useState(false);
  const [accessToken, setAccessToken] = useState(null); // Stocăm token-ul aici

  // Funcție pentru redirecționarea utilizatorului la backend pentru login
  const handleLogin = () => {
    window.location.href = 'http://localhost:8000/shortcuts/teams/login/';
  };

  // Funcție pentru a obține token-ul din URL după ce Microsoft redirecționează înapoi la aplicație
  const handleCallback = () => {
    const queryParams = new URLSearchParams(window.location.search);
    const token = queryParams.get('access_token');  // Extragem token-ul din URL
    if (token) {
      setAccessToken(token);  // Stocăm token-ul în state
      localStorage.setItem('access_token', token);  // Salvează token-ul în localStorage pentru utilizare ulterioară
    }
  };

  // Preluăm token-ul la montarea componentului, dacă există
  useEffect(() => {
    const token = localStorage.getItem('access_token');
    if (token) {
      setAccessToken(token);
    }
  }, []);

  // Funcție pentru preluarea contactelor
  const fetchContacts = async () => {
    setLoadingContacts(true);  // Afișăm mesajul de încărcare
    try {
      const token = accessToken || localStorage.getItem('access_token');  // Folosim token-ul din state sau localStorage
      const response = await axios.get('https://graph.microsoft.com/v1.0/me/contacts', {
        headers: {
          Authorization: `Bearer ${token}`  // Adăugăm token-ul în header-ul cererii
        }
      });
      setContacts(response.data.value);  // Stocăm contactele în state
    } catch (error) {
      console.error('Eroare la preluarea contactelor:', error);
    } finally {
      setLoadingContacts(false);  // Oprim afișarea mesajului de încărcare
    }
  };

  return (
    <div className="teams-container">
      <h1>Microsoft Teams</h1>
      <button onClick={handleLogin}>Conectare la Microsoft Teams</button>
      <button onClick={fetchContacts}>Preia Contactele</button>

      {loadingContacts && <p>Se încarcă contactele...</p>}

      <ul>
        {contacts.map(contact => (
          <li key={contact.id}>{contact.displayName}</li>
        ))}
      </ul>
    </div>
  );
};

export default MicrosoftTeams;
